In that case, you can create a separate index cache for each index file. This approach ensures that each index file has its own cache, which can be cleared independently when the corresponding index file is removed.

Here's a high-level example of how you can implement this in Python:

```python
import os
import pickle

class IndexCache:
    def __init__(self, cache_dir):
        self.cache_dir = cache_dir
        os.makedirs(self.cache_dir, exist_ok=True)

    def get(self, index_file):
        cache_file = os.path.join(self.cache_dir, f"{os.path.basename(index_file)}.cache")
        try:
            with open(cache_file, "rb") as f:
                return pickle.load(f)
        except FileNotFoundError:
            return None

    def set(self, index_file, value):
        cache_file = os.path.join(self.cache_dir, f"{os.path.basename(index_file)}.cache")
        with open(cache_file, "wb") as f:
            pickle.dump(value, f)

    def clear(self, index_file):
        cache_file = os.path.join(self.cache_dir, f"{os.path.basename(index_file)}.cache")
        try:
            os.remove(cache_file)
